from __future__ import print_function

import os
import sys
import re
import datetime
import subprocess
import errno

# Allowlisted compression formats and their properties
SUPPORTED_FORMATS = {
    'tar.gz': {
        'extension': '.tar.gz',
        'description': 'gzip compressed tar archive',
    },
    'tar.bz2': {
        'extension': '.tar.bz2',
        'description': 'bzip2 compressed tar archive',
    },
    'zip': {
        'extension': '.zip',
        'description': 'ZIP archive',
    },
    '7z': {
        'extension': '.7z',
        'description': '7-Zip archive',
    },
}


def validate_path(path):
    """Validate and normalize a filesystem path. Reject dangerous characters."""
    if not path:
        raise ValueError("Path cannot be empty.")

    # Resolve to absolute, real path (no symlink tricks)
    real_path = os.path.realpath(os.path.abspath(path))

    # Reject null bytes
    if '\x00' in real_path:
        raise ValueError("Path contains null bytes.")

    # Ensure the path exists
    if not os.path.exists(real_path):
        raise ValueError("Path does not exist: {0}".format(real_path))

    return real_path


def validate_format(fmt):
    """Validate the compression format against the allowlist."""
    if fmt not in SUPPORTED_FORMATS:
        raise ValueError(
            "Unsupported format: {0}. Supported formats: {1}".format(
                fmt, ', '.join(sorted(SUPPORTED_FORMATS.keys()))
            )
        )
    return fmt


def validate_output_dir(output_dir):
    """Validate and ensure the output directory exists."""
    real_dir = os.path.realpath(os.path.abspath(output_dir))

    if '\x00' in real_dir:
        raise ValueError("Output directory path contains null bytes.")

    if not os.path.isdir(real_dir):
        try:
            os.makedirs(real_dir)
            print("Created output directory: {0}".format(real_dir))
        except OSError as e:
            if e.errno != errno.EEXIST:
                raise ValueError("Cannot create output directory: {0}".format(e))

    if not os.access(real_dir, os.W_OK):
        raise ValueError("Output directory is not writable: {0}".format(real_dir))

    return real_dir


def generate_archive_name(source_path, fmt):
    """Generate a safe archive filename based on the source directory name and timestamp."""
    dir_name = os.path.basename(source_path)
    # Sanitize directory name: only allow alphanumeric, hyphens, underscores, dots
    safe_name = re.sub(r'[^a-zA-Z0-9._-]', '_', dir_name)
    if not safe_name:
        safe_name = 'backup'

    timestamp = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
    extension = SUPPORTED_FORMATS[fmt]['extension']
    return "{0}_{1}{2}".format(safe_name, timestamp, extension)


def find_executable(name):
    """Find an executable in PATH. Returns the full path or None."""
    # Only allow specific known executable names (allowlist)
    allowed_executables = {'tar', 'zip', '7z', '7za'}
    if name not in allowed_executables:
        return None

    path_dirs = os.environ.get('PATH', '/usr/bin:/bin:/usr/local/bin').split(os.pathsep)
    for directory in path_dirs:
        full_path = os.path.join(directory, name)
        if os.path.isfile(full_path) and os.access(full_path, os.X_OK):
            return full_path
    return None


def create_tar_gz(source_path, output_path):
    """Create a tar.gz archive using Python's tarfile module, falling back to tar command."""
    try:
        import tarfile
        print("Using Python tarfile module for tar.gz compression...")
        with tarfile.open(output_path, 'w:gz') as tar:
            tar.add(source_path, arcname=os.path.basename(source_path))
        return True
    except (ImportError, Exception) as e:
        print("Python tarfile failed ({0}), trying system tar...".format(e))

    tar_path = find_executable('tar')
    if tar_path is None:
        raise RuntimeError("Neither Python tarfile module nor system tar is available.")

    parent_dir = os.path.dirname(source_path)
    base_name = os.path.basename(source_path)

    # Use list-based subprocess call — no shell=True, no string interpolation
    cmd = [tar_path, '-czf', output_path, '-C', parent_dir, base_name]
    print("Running: {0}".format(' '.join(cmd)))
    ret = subprocess.call(cmd)
    if ret != 0:
        raise RuntimeError("tar command failed with exit code {0}".format(ret))
    return True


