def create_zip(source_path, output_path):
    """Create a ZIP archive using Python's zipfile module, falling back to system zip."""
    try:
        import zipfile
        print("Using Python zipfile module for ZIP compression...")
        with zipfile.ZipFile(output_path, 'w', zipfile.ZIP_DEFLATED) as zf:
            base_name = os.path.basename(source_path)
            for root, dirs, files in os.walk(source_path):
                for filename in files:
                    file_path = os.path.join(root, filename)
                    arcname = os.path.join(
                        base_name,
                        os.path.relpath(file_path, source_path)
                    )
                    zf.write(file_path, arcname)
                # Also add empty directories
                for dirname in dirs:
                    dir_path = os.path.join(root, dirname)
                    arcname = os.path.join(
                        base_name,
                        os.path.relpath(dir_path, source_path)
                    ) + '/'
                    zf.write(dir_path, arcname)
        return True
    except (ImportError, Exception) as e:
        print("Python zipfile failed ({0}), trying system zip...".format(e))

    zip_path = find_executable('zip')
    if zip_path is None:
        raise RuntimeError("Neither Python zipfile module nor system zip is available.")

    parent_dir = os.path.dirname(source_path)
    base_name = os.path.basename(source_path)

    # Use list-based subprocess call with -r for recursive
    cmd = [zip_path, '-r', output_path, base_name]
    print("Running: {0} (in directory {1})".format(' '.join(cmd), parent_dir))
    ret = subprocess.call(cmd, cwd=parent_dir)
    if ret != 0:
        raise RuntimeError("zip command failed with exit code {0}".format(ret))
    return True


def create_7z(source_path, output_path):
    """Create a 7z archive using the system 7z or 7za command."""
    # Try 7z first, then 7za
    exe_path = find_executable('7z')
    if exe_path is None:
        exe_path = find_executable('7za')
    if exe_path is None:
        raise RuntimeError(
            "7z/7za command not found. Install p7zip or p7zip-full package."
        )

    # Use list-based subprocess call — no shell=True
    cmd = [exe_path, 'a', output_path, source_path]
    print("Running: {0}".format(' '.join(cmd)))
    ret = subprocess.call(cmd)
    if ret != 0:
        raise RuntimeError("7z command failed with exit code {0}".format(ret))
    return True


# Map format names to their creation functions
FORMAT_HANDLERS = {
    'tar.gz': create_tar_gz,
    'tar.bz2': create_tar_bz2,
    'zip': create_zip,
    '7z': create_7z,
}


def create_backup(source_path, fmt, output_dir=None):
    """
    Create a backup archive of the given source directory.

    Args:
        source_path: Path to the directory to back up.
        fmt: Compression format (tar.gz, tar.bz2, zip, 7z).
        output_dir: Directory to store the archive (default: current directory).

    Returns:
        Path to the created archive file.
    """
    # Validate inputs
    source_path = validate_path(source_path)
    fmt = validate_format(fmt)

    if not os.path.isdir(source_path):
        raise ValueError("Source path is not a directory: {0}".format(source_path))

    if output_dir is None:
        output_dir = os.getcwd()
    output_dir = validate_output_dir(output_dir)

    archive_name = generate_archive_name(source_path, fmt)
    output_path = os.path.join(output_dir, archive_name)

    # Ensure we don't overwrite an existing file
    if os.path.exists(output_path):
        raise ValueError("Output file already exists: {0}".format(output_path))

    print("=" * 60)
    print("Backup Configuration:")
    print("  Source:      {0}".format(source_path))
    print("  Format:      {0} ({1})".format(fmt, SUPPORTED_FORMATS[fmt]['description']))
    print("  Output:      {0}".format(output_path))
    print("=" * 60)

    handler = FORMAT_HANDLERS[fmt]
    handler(source_path, output_path)

    if os.path.exists(output_path):
        size = os.path.getsize(output_path)
        print("\nBackup created successfully!")
        print("  File: {0}".format(output_path))
        print("  Size: {0}".format(format_size(size)))
    else:
        raise RuntimeError("Archive file was not created.")

    return output_path


def format_size(size_bytes):
    """Format a byte count into a human-readable string."""
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size_bytes < 1024.0:
            return "{0:.1f} {1}".format(size_bytes, unit)
        size_bytes /= 1024.0
    return "{0:.1f} PB".format(size_bytes)


def print_usage():
    """Print usage information."""
    script_name = os.path.basename(sys.argv[0])
